function MobileMatchResultWizard({
  match,
  darkMode,
  step,
  onStepChange,
  scoreForm,
  setScoreForm,
  onStatusChange,
  onWalkoverWinnerChange,
  refereeOptions,
  homeRoster,
  awayRoster,
  participantSelection,
  onToggleParticipant,
  onSelectAllParticipants,
  onClearParticipants,
  homeSelectedRows,
  awaySelectedRows,
  playerStatsForm,
  mvpPlayerId,
  onToggleMvp,
  onStatChange,
  homeTotals,
  awayTotals,
  homeUnassignedGoals,
  awayUnassignedGoals,
  onSave,
  saving,
}) {
  const textMuted = darkMode ? "text-gray-400" : "text-gray-500";
  const currentIndex = Math.max(0, MOBILE_RESULT_STEPS.findIndex((item) => item.key === step));
  const currentStep = MOBILE_RESULT_STEPS[currentIndex] || MOBILE_RESULT_STEPS[0];
  const isLast = currentIndex === MOBILE_RESULT_STEPS.length - 1;
  const statsDisabled = saving || scoreForm.status !== "completed";

  const goTo = (index) => {
    const next = MOBILE_RESULT_STEPS[index];
    if (next) onStepChange(next.key);
  };

  const nextLabels = {
    "home-attendance": "Dalej: obecnosc gosci",
    "away-attendance": "Dalej: wynik",
    result: "Dalej: statystyki gospodarzy",
    "home-stats": "Dalej: statystyki gosci",
  };

  return (
    <div className={`rounded-2xl border p-4 space-y-4 ${darkMode ? "border-white/10 bg-black/10" : "border-gray-200 bg-gray-50"}`}>
      <div>
        <div className={`text-xs font-bold uppercase tracking-[0.16em] ${textMuted}`}>
          Krok {currentIndex + 1} z {MOBILE_RESULT_STEPS.length}
        </div>
        <div className="mt-1 text-xl font-black leading-tight">{currentStep.label}</div>
        <div className="mt-3 grid grid-cols-5 gap-1.5">
          {MOBILE_RESULT_STEPS.map((item, index) => (
            <button
              key={item.key}
              type="button"
              onClick={() => goTo(index)}
              className={`h-2 rounded-full transition-colors ${
                index <= currentIndex
                  ? "bg-emerald-500"
                  : darkMode
                    ? "bg-white/15"
                    : "bg-gray-300"
              }`}
              aria-label={item.label}
            />
          ))}
        </div>
      </div>

      {currentStep.key === "home-attendance" && (
        <MobileAttendanceStep
          teamKey="home"
          teamName={match.home_team_name}
          roster={homeRoster}
          selectedIds={participantSelection.home}
          onTogglePlayer={onToggleParticipant}
          onSelectAll={onSelectAllParticipants}
          onClear={onClearParticipants}
          darkMode={darkMode}
          disabled={saving}
        />
      )}

      {currentStep.key === "away-attendance" && (
        <MobileAttendanceStep
          teamKey="away"
          teamName={match.away_team_name}
          roster={awayRoster}
          selectedIds={participantSelection.away}
          onTogglePlayer={onToggleParticipant}
          onSelectAll={onSelectAllParticipants}
          onClear={onClearParticipants}
          darkMode={darkMode}
          disabled={saving}
        />
      )}

      {currentStep.key === "result" && (
        <MobileResultStep
          match={match}
          scoreForm={scoreForm}
          setScoreForm={setScoreForm}
          onStatusChange={onStatusChange}
          onWalkoverWinnerChange={onWalkoverWinnerChange}
          refereeOptions={refereeOptions}
          darkMode={darkMode}
          disabled={saving}
        />
      )}

      {currentStep.key === "home-stats" && (
        <MobileStatsStep
          title={match.home_team_name}
          score={parseScoreValue(scoreForm.home_goals)}
          totals={homeTotals}
          unassignedGoals={homeUnassignedGoals}
          players={homeSelectedRows}
          playerStatsForm={playerStatsForm}
          mvpPlayerId={mvpPlayerId}
          onToggleMvp={onToggleMvp}
          onStatChange={onStatChange}
          darkMode={darkMode}
          disabled={statsDisabled}
          textMuted={textMuted}
        />
      )}

      {currentStep.key === "away-stats" && (
        <MobileStatsStep
          title={match.away_team_name}
          score={parseScoreValue(scoreForm.away_goals)}
          totals={awayTotals}
          unassignedGoals={awayUnassignedGoals}
          players={awaySelectedRows}
          playerStatsForm={playerStatsForm}
          mvpPlayerId={mvpPlayerId}
          onToggleMvp={onToggleMvp}
          onStatChange={onStatChange}
          darkMode={darkMode}
          disabled={statsDisabled}
          textMuted={textMuted}
        />
      )}

      {scoreForm.status !== "completed" && (currentStep.key === "home-stats" || currentStep.key === "away-stats") && (
        <div className={`rounded-xl border px-3 py-2 text-sm ${darkMode ? "border-blue-400/20 bg-blue-500/10 text-blue-200" : "border-blue-200 bg-blue-50 text-blue-800"}`}>
          Statystyki zawodnikow sa aktywne tylko dla meczu ze statusem "Zakonczony".
        </div>
      )}

      <div className="grid grid-cols-2 gap-2 pt-1">
        <button
          type="button"
          onClick={() => goTo(currentIndex - 1)}
          disabled={saving || currentIndex === 0}
          className={`flex min-h-[48px] items-center justify-center gap-2 rounded-xl border px-3 py-3 text-sm font-semibold ${
            darkMode ? "border-white/10 bg-white/5" : "border-gray-200 bg-white"
          } disabled:opacity-45`}
        >
          <ArrowLeft size={16} />
          Wstecz
        </button>

        <button
          type="button"
          onClick={isLast ? onSave : () => goTo(currentIndex + 1)}
          disabled={saving}
          className="flex min-h-[48px] items-center justify-center gap-2 rounded-xl bg-green-500 px-3 py-3 text-sm font-bold text-black hover:bg-green-400 disabled:opacity-60"
        >
          {saving ? (
            <Loader2 size={16} className="animate-spin" />
          ) : isLast ? (
            <Save size={16} />
          ) : (
            <ArrowRight size={16} />
          )}
          {isLast ? "Zapisz mecz" : nextLabels[currentStep.key] || "Dalej"}
        </button>
      </div>
    </div>
  );
}

export default function AdminMatchResults({ darkMode }) {
  const [seasons, setSeasons] = useState([]);
  const [leagues, setLeagues] = useState([]);
  const [referees, setReferees] = useState([]);
  const [matches, setMatches] = useState([]);
  const [resultEditsByMatchId, setResultEditsByMatchId] = useState({});
  const [availableRounds, setAvailableRounds] = useState([]);
  const [selectedSeason, setSelectedSeason] = useState("");
  const [selectedLeague, setSelectedLeague] = useState("");
  const [selectedRound, setSelectedRound] = useState("");
  const [expandedMatch, setExpandedMatch] = useState(null);
  const [matchEvents, setMatchEvents] = useState([]);
  const [matchLineups, setMatchLineups] = useState([]);
  const [homeRoster, setHomeRoster] = useState([]);
  const [awayRoster, setAwayRoster] = useState([]);
  const [participantSelection, setParticipantSelection] = useState(EMPTY_TEAM_SELECTION);
  const [participantDrafts, setParticipantDrafts] = useState(EMPTY_TEAM_SELECTION);
  const [pickerOpen, setPickerOpen] = useState(null);
  const [mobileWizardStep, setMobileWizardStep] = useState(MOBILE_RESULT_STEPS[0].key);
  const [playerStatsForm, setPlayerStatsForm] = useState({});
  const [scoreForm, setScoreForm] = useState({});
  const [mvpPlayerId, setMvpPlayerId] = useState("");
  const [loading, setLoading] = useState(true);
  const [loadingExpandedMatch, setLoadingExpandedMatch] = useState(false);
  const [savingMatchData, setSavingMatchData] = useState(false);
  const [refereesTableMissing, setRefereesTableMissing] = useState(false);
  const [resultEditsTableMissing, setResultEditsTableMissing] = useState(false);
  const [alert, setAlert] = useState({ type: null, message: null });

  const card = darkMode ? "bg-white/5 border-white/10" : "bg-white border-gray-200";
  const textMuted = darkMode ? "text-gray-400" : "text-gray-500";

  const resetExpandedEditor = useCallback(() => {
    setMatchEvents([]);
    setMatchLineups([]);
    setHomeRoster([]);
    setAwayRoster([]);
    setParticipantSelection(EMPTY_TEAM_SELECTION);
    setParticipantDrafts(EMPTY_TEAM_SELECTION);
    setPickerOpen(null);
    setMobileWizardStep(MOBILE_RESULT_STEPS[0].key);
    setPlayerStatsForm({});
    setMvpPlayerId("");
  }, []);

  const loadReferees = useCallback(async () => {
    try {
      const { data, error } = await supabase
        .from("referees")
        .select("id, full_name, is_active")
        .order("is_active", { ascending: false })
        .order("full_name");

      if (error) throw error;

      setReferees(data || []);
      setRefereesTableMissing(false);
    } catch (error) {
      const message = String(error?.message || "");
      setReferees([]);
      setRefereesTableMissing(message.toLowerCase().includes("referees"));
      if (!message.toLowerCase().includes("referees")) {
        setAlert({ type: "error", message: message || "Nie udalo sie zaladowac listy sedziow." });
      }
    }
  }, []);

  const loadBase = useCallback(async () => {
    const [{ data: seasonRows, error: seasonError }, { data: leagueRows, error: leagueError }] = await Promise.all([
      supabase.from("seasons").select("*").order("year", { ascending: false }),
      supabase.from("leagues").select("*").order("display_order"),
    ]);

    if (seasonError || leagueError) {
      setAlert({ type: "error", message: seasonError?.message || leagueError?.message || "Nie udalo sie zaladowac danych bazowych." });
      setLoading(false);
      return;
    }

    setSeasons(seasonRows || []);
    setLeagues(leagueRows || []);
    if (seasonRows?.length) setSelectedSeason(seasonRows[0].id);
    if (leagueRows?.length) setSelectedLeague(leagueRows[0].id);
    setLoading(false);
  }, []);

  const loadResultEdits = useCallback(async (matchRows) => {
    const matchIds = uniqueIds((matchRows || []).map((match) => match.id));

    if (matchIds.length === 0) {
      setResultEditsByMatchId({});
      return {};
    }

    const { data, error } = await supabase
      .from("match_result_edits")
      .select("match_id, editor_name_snapshot, edited_at")
      .in("match_id", matchIds);

    if (error) {
      const message = String(error?.message || "");
      const lowerMessage = message.toLowerCase();
      const tableMissing =
        lowerMessage.includes("match_result_edits") ||
        (lowerMessage.includes("relation") && lowerMessage.includes("does not exist"));

      setResultEditsByMatchId({});
      setResultEditsTableMissing(tableMissing);

      if (!tableMissing) {
        console.warn("Match result edits fetch:", message);
      }

      return {};
    }

    const nextMap = {};
    for (const row of data || []) {
      if (row.match_id) nextMap[row.match_id] = row;
    }

    setResultEditsTableMissing(false);
    setResultEditsByMatchId(nextMap);
    return nextMap;
  }, []);

  const loadMatches = useCallback(async () => {
    if (!selectedSeason || !selectedLeague) return [];

    const { data, error } = await supabase
      .from("v_matches")
      .select("*")
      .eq("season_id", selectedSeason)
      .eq("league_id", selectedLeague)
      .order("round")
      .order("match_date")
      .order("match_time");

    if (error) {
      setAlert({ type: "error", message: error.message });
      setMatches([]);
      setAvailableRounds([]);
      return [];
    }

    const allRows = data || [];
    const rounds = uniqueIds(allRows.map((match) => String(match.round))).sort((a, b) => Number(a) - Number(b));
    const filtered = selectedRound ? allRows.filter((match) => String(match.round) === String(selectedRound)) : allRows;

    setAvailableRounds(rounds);
    setMatches(filtered);
    await loadResultEdits(filtered);
    return allRows;
  }, [selectedSeason, selectedLeague, selectedRound, loadResultEdits]);

  const selectedSeasonObj = useMemo(
    () => seasons.find((season) => season.id === selectedSeason),
    [seasons, selectedSeason]
  );

  const isEditable = selectedSeasonObj?.status === "active";
  const roundOptions = useMemo(
    () => availableRounds.map((round) => ({ value: round, label: `Kolejka ${round}` })),
    [availableRounds]
  );
  const refereeOptions = useMemo(
    () =>
      (referees || [])
        .filter((referee) => referee.is_active || referee.id === scoreForm.referee_id)
        .map((referee) => ({
          value: referee.id,
          label: referee.is_active ? referee.full_name : `${referee.full_name} (archiwalny)`,
        })),
    [referees, scoreForm.referee_id]
  );

  useEffect(() => {
    loadBase();
    loadReferees();
  }, [loadBase, loadReferees]);

  useEffect(() => {
    function handleRefereesRefresh() {
      loadReferees();
    }

    window.addEventListener("mlpn:referees-updated", handleRefereesRefresh);
    return () => window.removeEventListener("mlpn:referees-updated", handleRefereesRefresh);
  }, [loadReferees]);

  useEffect(() => {
    if (!selectedSeason || !selectedLeague) return;
    setExpandedMatch(null);
    resetExpandedEditor();
    loadMatches();
  }, [selectedSeason, selectedLeague, selectedRound, loadMatches, resetExpandedEditor]);

  const statusLabel = (status) => (
    status === "completed" ? "Zakonczony" :
    status === "walkover_home" ? "Walkower (gosp.)" :
    status === "walkover_away" ? "Walkower (gosc)" :
    status === "postponed" ? "Przelozony" :
    status === "cancelled" ? "Odwolany" :
    status === "unplayed" ? "Nierozegrany" :
    status === "live" ? "W trakcie" :
    "Zaplanowany"
  );

  const openMatchEditor = useCallback(async (match, forceOpen = false) => {
    if (!match?.id) return;

    if (!forceOpen && expandedMatch === match.id) {
      setExpandedMatch(null);
      resetExpandedEditor();
      return;
    }

    setExpandedMatch(match.id);
    setLoadingExpandedMatch(true);
    setPickerOpen(null);
    setMobileWizardStep(MOBILE_RESULT_STEPS[0].key);

    const rawStatus = match.status || "scheduled";
    const isWalkover = rawStatus === "walkover_home" || rawStatus === "walkover_away";
    setScoreForm({
      home_goals: match.home_goals ?? "",
      away_goals: match.away_goals ?? "",
      status: isWalkover ? "walkover" : rawStatus,
      walkover_winner: rawStatus === "walkover_away" ? "away" : "home",
      referee_id: match.referee_id || "",
      video_url: match.video_url || "",
    });

    try {
      const [eventsResult, homeRosterResult, awayRosterResult, lineupsResult] = await Promise.all([
        supabase
          .from("match_events")
          .select(
            "id, event_type, team_id, player_id, assist_player_id, minute, event_order, is_own_goal, is_penalty, notes, player:players!match_events_player_id_fkey(id, display_name, position), assist:players!match_events_assist_player_id_fkey(id, display_name, position)"
          )
          .eq("match_id", match.id)
          .order("event_order")
          .order("minute"),
        supabase
          .from("team_players")
          .select("player_id, is_captain, shirt_number, players(id, display_name, position)")
          .eq("team_id", match.home_team_id)
          .eq("season_id", match.season_id)
          .eq("league_id", match.league_id)
          .is("left_date", null),
        supabase
          .from("team_players")
          .select("player_id, is_captain, shirt_number, players(id, display_name, position)")
          .eq("team_id", match.away_team_id)
          .eq("season_id", match.season_id)
          .eq("league_id", match.league_id)
          .is("left_date", null),
        supabase
          .from("match_lineups")
          .select("id, team_id, player_id, is_starter, shirt_number, position_played, players(id, display_name, position)")
          .eq("match_id", match.id),
      ]);

      const error =
        eventsResult.error ||
        homeRosterResult.error ||
        awayRosterResult.error ||
        lineupsResult.error;

      if (error) throw error;

      const eventRows = eventsResult.data || [];
      const lineupRows = lineupsResult.data || [];
      const nextHomeRoster = buildRosterRows(
        homeRosterResult.data || [],
        lineupRows,
        eventRows,
        match.home_team_id
      );
      const nextAwayRoster = buildRosterRows(
        awayRosterResult.data || [],
        lineupRows,
        eventRows,
        match.away_team_id
      );

      const nextSelection = {
        home: sortPlayerIdsByRoster(buildSelectedIds(lineupRows, eventRows, match.home_team_id), nextHomeRoster),
        away: sortPlayerIdsByRoster(buildSelectedIds(lineupRows, eventRows, match.away_team_id), nextAwayRoster),
      };
      const nextStats = buildPlayerStatsFromEvents(eventRows);

      for (const playerId of [...nextSelection.home, ...nextSelection.away]) {
        if (!nextStats[playerId]) nextStats[playerId] = createEmptyPlayerStats();
      }

      setMatchEvents(eventRows);
      setMatchLineups(lineupRows);
      setHomeRoster(nextHomeRoster);
      setAwayRoster(nextAwayRoster);
      setParticipantSelection(nextSelection);
      setParticipantDrafts(nextSelection);
      setPlayerStatsForm(nextStats);
      setMvpPlayerId(match.mvp_player_id || "");
    } catch (error) {
      setAlert({ type: "error", message: error.message || "Nie udalo sie zaladowac danych meczu." });
      resetExpandedEditor();
    } finally {
      setLoadingExpandedMatch(false);
    }
  }, [expandedMatch, resetExpandedEditor]);

  const allSelectedPlayerIds = useMemo(
    () => uniqueIds([...participantSelection.home, ...participantSelection.away]),
    [participantSelection]
  );

  const homeSelectedRows = useMemo(() => {
    const map = new Map(homeRoster.map((player) => [player.id, player]));
    return participantSelection.home.map((playerId) => map.get(playerId)).filter(Boolean);
  }, [homeRoster, participantSelection.home]);

  const awaySelectedRows = useMemo(() => {
    const map = new Map(awayRoster.map((player) => [player.id, player]));
    return participantSelection.away.map((playerId) => map.get(playerId)).filter(Boolean);
  }, [awayRoster, participantSelection.away]);

  function togglePicker(teamKey) {
    setParticipantDrafts((prev) => ({
      ...prev,
      [teamKey]: [...participantSelection[teamKey]],
    }));
    setPickerOpen((current) => (current === teamKey ? null : teamKey));
  }

  function toggleDraftPlayer(teamKey, playerId) {
    const roster = teamKey === "home" ? homeRoster : awayRoster;
    setParticipantDrafts((prev) => {
      const current = new Set(prev[teamKey] || []);
      if (current.has(playerId)) current.delete(playerId);
      else current.add(playerId);
      return {
        ...prev,
        [teamKey]: sortPlayerIdsByRoster(Array.from(current), roster),
      };
    });
  }

  function commitParticipantSelection(teamKey, rawPlayerIds) {
    const roster = teamKey === "home" ? homeRoster : awayRoster;
    const nextTeamIds = sortPlayerIdsByRoster(rawPlayerIds || [], roster);
    const nextSelection = {
      ...participantSelection,
      [teamKey]: nextTeamIds,
    };
    const nextSelectedIds = uniqueIds([...nextSelection.home, ...nextSelection.away]);

    setParticipantSelection(nextSelection);
    setParticipantDrafts(nextSelection);
    setPlayerStatsForm((prev) => {
      const next = {};
      for (const playerId of nextSelectedIds) {
        next[playerId] = prev[playerId] || createEmptyPlayerStats();
      }
      return next;
    });
    if (mvpPlayerId && !nextSelectedIds.includes(mvpPlayerId)) {
      setMvpPlayerId("");
    }
  }

  function applyParticipantSelection(teamKey) {
    commitParticipantSelection(teamKey, participantDrafts[teamKey]);
    setPickerOpen(null);
  }

  function toggleParticipantSelection(teamKey, playerId) {
    const current = new Set(participantSelection[teamKey] || []);
    if (current.has(playerId)) current.delete(playerId);
    else current.add(playerId);
    commitParticipantSelection(teamKey, Array.from(current));
  }

  function selectAllParticipants(teamKey) {
    const roster = teamKey === "home" ? homeRoster : awayRoster;
    commitParticipantSelection(teamKey, roster.map((player) => player.id));
  }

  function clearParticipants(teamKey) {
    commitParticipantSelection(teamKey, []);
  }

  function updatePlayerStat(playerId, field, value) {
    setPlayerStatsForm((prev) => {
      const current = prev[playerId] || createEmptyPlayerStats();
      const next = {
        ...prev,
        [playerId]: { ...current },
      };

      if (field === "yellow") {
        const normalized = normalizeCounterInput(value, 2);
        next[playerId].yellow = normalized;
        if (parseCount(normalized) === 2) {
          next[playerId].red = "1";
        }
      } else if (field === "red") {
        next[playerId].red = normalizeCounterInput(value, 1);
      } else {
        next[playerId][field] = normalizeCounterInput(value, 20);
      }

      return next;
    });
  }

  function toggleMvp(playerId) {
    setMvpPlayerId((current) => (current === playerId ? "" : playerId));
  }

  function updateScoreStatus(nextStatus) {
    setScoreForm((prev) => {
      const next = { ...prev, status: nextStatus };
      if (nextStatus === "walkover") {
        const winner = next.walkover_winner || "home";
        next.walkover_winner = winner;
        next.home_goals = winner === "home" ? 3 : 0;
        next.away_goals = winner === "away" ? 3 : 0;
      }
      if (["scheduled", "postponed", "cancelled", "unplayed"].includes(nextStatus)) {
        next.home_goals = "";
        next.away_goals = "";
      }
      return next;
    });
  }

  function updateWalkoverWinner(winner) {
    setScoreForm((prev) => ({
      ...prev,
      walkover_winner: winner,
      home_goals: winner === "home" ? 3 : 0,
      away_goals: winner === "away" ? 3 : 0,
    }));
  }

  async function saveMatch(match) {
    if (!match?.id) return;

    setSavingMatchData(true);
    try {
      const resolvedStatus = scoreForm.status === "walkover"
        ? (scoreForm.walkover_winner === "away" ? "walkover_away" : "walkover_home")
        : scoreForm.status;
      const normalizedVideoUrl = String(scoreForm.video_url || "").trim();

      const noScoreStatuses = new Set(["scheduled", "postponed", "cancelled", "unplayed"]);
      let homeGoals = parseScoreValue(scoreForm.home_goals);
      let awayGoals = parseScoreValue(scoreForm.away_goals);

      if (resolvedStatus === "walkover_home") {
        homeGoals = homeGoals ?? 3;
        awayGoals = awayGoals ?? 0;
      } else if (resolvedStatus === "walkover_away") {
        homeGoals = homeGoals ?? 0;
        awayGoals = awayGoals ?? 3;
      } else if (noScoreStatuses.has(resolvedStatus)) {
        homeGoals = null;
        awayGoals = null;
      }

      let lineupsPayload = [];
      let eventsPayload = [];
      let nextMvpPlayerId = null;

      if (resolvedStatus === "completed") {
        if (homeGoals === null || awayGoals === null) {
          throw new Error("Przy zakonczonym meczu wpisz wynik dla obu druzyn.");
        }

        const hasSelectedParticipants =
          participantSelection.home.length > 0 || participantSelection.away.length > 0;
        const hasPlayerStats = hasAnyPlayerStats(playerStatsForm);

        if (!hasSelectedParticipants && (hasPlayerStats || mvpPlayerId)) {
          throw new Error("Aby zapisac statystyki zawodnikow lub MVP, najpierw wybierz uczestnikow meczu.");
        }

        const homeTotals = teamTotals(participantSelection.home, playerStatsForm);
        const awayTotals = teamTotals(participantSelection.away, playerStatsForm);
        const preservedHomeOwnGoals = (matchEvents || []).filter(
          (event) => event.event_type === "GOAL" && event.is_own_goal && event.team_id === match.away_team_id
        ).length;
        const preservedAwayOwnGoals = (matchEvents || []).filter(
          (event) => event.event_type === "GOAL" && event.is_own_goal && event.team_id === match.home_team_id
        ).length;

        if (hasSelectedParticipants) {
          if (homeTotals.goals + preservedHomeOwnGoals > homeGoals) {
            throw new Error(`Suma goli zawodnikow druzyny ${match.home_team_name} nie moze byc wieksza niz wynik meczu.`);
          }
          if (awayTotals.goals + preservedAwayOwnGoals > awayGoals) {
            throw new Error(`Suma goli zawodnikow druzyny ${match.away_team_name} nie moze byc wieksza niz wynik meczu.`);
          }
          if (homeTotals.assists > homeTotals.goals) {
            throw new Error(`Za duzo asyst wpisano dla druzyny ${match.home_team_name}.`);
          }
          if (awayTotals.assists > awayTotals.goals) {
            throw new Error(`Za duzo asyst wpisano dla druzyny ${match.away_team_name}.`);
          }
          const homeAssistError = getAssistDistributionError(
            match.home_team_name,
            participantSelection.home,
            playerStatsForm,
            homeSelectedRows
          );
          if (homeAssistError) throw new Error(homeAssistError);
          const awayAssistError = getAssistDistributionError(
            match.away_team_name,
            participantSelection.away,
            playerStatsForm,
            awaySelectedRows
          );
          if (awayAssistError) throw new Error(awayAssistError);
          if (mvpPlayerId && !allSelectedPlayerIds.includes(mvpPlayerId)) {
            throw new Error("MVP musi byc wybrany sposrod zawodnikow uczestniczacych w meczu.");
          }

          lineupsPayload = buildLineupsPayload(match, participantSelection, homeRoster, awayRoster);
          eventsPayload = buildMatchEventsPayload(match, participantSelection, playerStatsForm, matchEvents);
          nextMvpPlayerId = mvpPlayerId || null;
        }
      }

      const updatePayload = {
        home_goals: homeGoals,
        away_goals: awayGoals,
        status: resolvedStatus,
        video_url: normalizedVideoUrl || null,
        mvp_player_id: nextMvpPlayerId,
      };

      if (!refereesTableMissing) {
        updatePayload.referee_id = scoreForm.referee_id || null;
        updatePayload.referee = referees.find((referee) => referee.id === scoreForm.referee_id)?.full_name || null;
      }

      const { error: updateError } = await supabase
        .from("matches")
        .update(updatePayload)
        .eq("id", match.id);

      if (updateError) throw updateError;

      const existingEventIds = (matchEvents || []).map((event) => event.id).filter(Boolean);
      if (existingEventIds.length > 0) {
        const { error: suspensionDeleteError } = await supabase
          .from("suspensions")
          .delete()
          .in("triggering_event_id", existingEventIds);
        if (suspensionDeleteError) throw suspensionDeleteError;
      }

      const { error: deleteEventsError } = await supabase
        .from("match_events")
        .delete()
        .eq("match_id", match.id);
      if (deleteEventsError) throw deleteEventsError;

      const { error: deleteLineupsError } = await supabase
        .from("match_lineups")
        .delete()
        .eq("match_id", match.id);
      if (deleteLineupsError) throw deleteLineupsError;

      if (lineupsPayload.length > 0) {
        const { error: insertLineupsError } = await supabase
          .from("match_lineups")
          .insert(lineupsPayload);
        if (insertLineupsError) throw insertLineupsError;
      }

      if (eventsPayload.length > 0) {
        const { error: insertEventsError } = await supabase
          .from("match_events")
          .insert(eventsPayload);
        if (insertEventsError) throw insertEventsError;
      }

      const { error: auditError } = await supabase.rpc("touch_match_result_edit", { p_match_id: match.id });
      if (auditError) {
        console.warn("Match result audit update:", auditError.message);
      }

      setAlert({ type: "success", message: "Mecz zostal zapisany." });
      const allRows = await loadMatches();
      const refreshedMatch = allRows.find((item) => item.id === match.id) || { ...match, ...updatePayload };
      await openMatchEditor(refreshedMatch, true);
    } catch (error) {
      setAlert({ type: "error", message: error.message || "Nie udalo sie zapisac meczu." });
    } finally {
      setSavingMatchData(false);
    }
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <div className="w-8 h-8 border-2 border-yellow-500 border-t-transparent rounded-full animate-spin" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold">Wyniki meczow</h2>

      <AdminAlert
        type={alert.type}
        message={alert.message}
        onClose={() => setAlert({ type: null, message: null })}
      />

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <AdminFormField
          label="Sezon"
          name="season"
          type="select"
          value={selectedSeason}
          onChange={(e) => setSelectedSeason(e.target.value)}
          darkMode={darkMode}
          options={seasons.map((season) => ({ value: season.id, label: season.name }))}
        />
        <AdminFormField
          label="Liga"
          name="league"
          type="select"
          value={selectedLeague}
          onChange={(e) => setSelectedLeague(e.target.value)}
          darkMode={darkMode}
          options={leagues.map((league) => ({ value: league.id, label: league.name }))}
        />
        <AdminFormField
          label="Kolejka"
          name="round"
          type="select"
          value={selectedRound}
          onChange={(e) => setSelectedRound(e.target.value)}
          darkMode={darkMode}
          options={[{ value: "", label: "Wszystkie" }, ...roundOptions]}
        />
      </div>

      {!isEditable && selectedSeasonObj && (
        <div className={`rounded-xl border p-3 text-sm ${darkMode ? "border-orange-500/30 bg-orange-500/10 text-orange-300" : "border-orange-200 bg-orange-50 text-orange-800"}`}>
          Sezon "{selectedSeasonObj.name}" ma status <strong>{selectedSeasonObj.status}</strong> - edycja wynikow i skladu jest zablokowana. Mozesz jednak podejrzec dane meczu i zarzadzac galeria.
        </div>
      )}

      {refereesTableMissing && (
        <div className={`rounded-xl border p-3 text-sm ${darkMode ? "border-amber-400/30 bg-amber-500/10 text-amber-200" : "border-amber-200 bg-amber-50 text-amber-800"}`}>
          Brakuje tabeli sedziow w bazie. W Supabase uruchom plik <code className="font-mono">supabase/migrations/015_referees.sql</code>, zeby wybierac sedziow z listy.
        </div>
      )}

      {resultEditsTableMissing && (
        <div className={`rounded-xl border p-3 text-sm ${darkMode ? "border-amber-400/30 bg-amber-500/10 text-amber-200" : "border-amber-200 bg-amber-50 text-amber-800"}`}>
          Brakuje historii edycji wynikow w bazie. W Supabase uruchom plik <code className="font-mono">supabase/migrations/020_match_result_edits.sql</code>.
        </div>
      )}

      {matches.length === 0 ? (
        <div className={`rounded-2xl border p-8 text-center ${card}`}>
          <p className={textMuted}>Brak meczow. Wygeneruj terminarz w zakladce "Terminarz".</p>
        </div>
      ) : (
        <div className="space-y-3">
          {matches.map((match) => {
            const homeTotals = teamTotals(participantSelection.home, playerStatsForm);
            const awayTotals = teamTotals(participantSelection.away, playerStatsForm);
            const currentHomeScore =
              expandedMatch === match.id ? parseScoreValue(scoreForm.home_goals) : parseScoreValue(match.home_goals);
            const currentAwayScore =
              expandedMatch === match.id ? parseScoreValue(scoreForm.away_goals) : parseScoreValue(match.away_goals);
            const homeUnassignedGoals =
              currentHomeScore === null ? 0 : Math.max(currentHomeScore - homeTotals.goals, 0);
            const awayUnassignedGoals =
              currentAwayScore === null ? 0 : Math.max(currentAwayScore - awayTotals.goals, 0);
            const resultEditInfo = resultEditsByMatchId[match.id];
            const resultEditorName = resultEditInfo?.editor_name_snapshot || "brak danych";
            const resultEditTime = formatResultEditTimestamp(resultEditInfo?.edited_at);

            return (
              <div key={match.id} className={`rounded-2xl border overflow-hidden ${card}`}>
                <button
                  type="button"
                  onClick={() => openMatchEditor(match)}
                  className="w-full px-4 py-3 flex items-center justify-between gap-3 hover:bg-white/5 transition-colors"
                >
                  <div className="hidden md:flex items-center gap-3 min-w-0">
                    <span className={`text-xs ${textMuted} w-8 flex-shrink-0`}>K{match.round}</span>
                    <span className="font-medium truncate">{match.home_team_name}</span>
                    {match.status === "completed" || String(match.status || "").startsWith("walkover") ? (
                      <span className="font-bold text-lg px-2 flex-shrink-0">
                        {match.home_goals} : {match.away_goals}
                      </span>
                    ) : (
                      <span className={`px-2 ${textMuted}`}>vs</span>
                    )}
                    <span className="font-medium truncate">{match.away_team_name}</span>
                  </div>

                  <div className="hidden md:flex items-center gap-2 flex-shrink-0">
                    <span className={`text-xs px-2 py-0.5 rounded-full font-medium ${
                      match.status === "completed" ? "bg-green-500/20 text-green-400" :
                      String(match.status || "").startsWith("walkover") ? "bg-orange-500/20 text-orange-400" :
                      match.status === "postponed" ? "bg-blue-500/20 text-blue-400" :
                      match.status === "cancelled" ? "bg-red-500/20 text-red-400" :
                      match.status === "unplayed" ? "bg-slate-500/20 text-slate-300" :
                      darkMode ? "bg-white/10 text-gray-400" : "bg-gray-100 text-gray-500"
                    }`}>
                      {statusLabel(match.status)}
                    </span>
                    <span className={`text-xs ${textMuted}`}>{match.match_date || "—"}</span>
                    {expandedMatch === match.id ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                  </div>

                  <div className="md:hidden w-full space-y-2">
                    <div className="flex items-center justify-between gap-2">
                      <span className={`text-xs ${textMuted}`}>Kolejka {match.round}</span>
                      <span className={`text-xs ${textMuted}`}>{match.match_date || "-"}</span>
                    </div>

                    <div className="grid grid-cols-[1fr_auto_1fr_auto] items-center gap-2">
                      <span className="text-sm font-medium leading-tight text-left break-words">
                        {match.home_team_name}
                      </span>
                      {match.status === "completed" || String(match.status || "").startsWith("walkover") ? (
                        <span className="font-bold text-lg px-2 whitespace-nowrap">
                          {match.home_goals} : {match.away_goals}
                        </span>
                      ) : (
                        <span className={`px-2 text-sm ${textMuted}`}>vs</span>
                      )}
                      <span className="text-sm font-medium leading-tight text-right break-words">
                        {match.away_team_name}
                      </span>
                      {expandedMatch === match.id ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
                    </div>

                    <div className="flex flex-wrap items-center gap-2">
                      <span className={`text-xs px-2 py-1 rounded-full font-medium ${
                        match.status === "completed" ? "bg-green-500/20 text-green-400" :
                        String(match.status || "").startsWith("walkover") ? "bg-orange-500/20 text-orange-400" :
                        match.status === "postponed" ? "bg-blue-500/20 text-blue-400" :
                        match.status === "cancelled" ? "bg-red-500/20 text-red-400" :
                        match.status === "unplayed" ? "bg-slate-500/20 text-slate-300" :
                        darkMode ? "bg-white/10 text-gray-400" : "bg-gray-100 text-gray-500"
                      }`}>
                        {statusLabel(match.status)}
                      </span>
                    </div>
                  </div>
                </button>

                {expandedMatch === match.id && (
                  <div className={`border-t px-4 py-4 space-y-4 ${darkMode ? "border-white/10" : "border-gray-200"}`}>
                    {loadingExpandedMatch ? (
                      <div className={`flex items-center gap-2 text-sm ${textMuted}`}>
                        <Loader2 size={16} className="animate-spin" />
                        Ladowanie danych meczu...
                      </div>
                    ) : (
                      <>
                        {isEditable ? (
                          <>
                            <div className="md:hidden">
                              <MobileMatchResultWizard
                                match={match}
                                darkMode={darkMode}
                                step={mobileWizardStep}
                                onStepChange={setMobileWizardStep}
                                scoreForm={scoreForm}
                                setScoreForm={setScoreForm}
                                onStatusChange={updateScoreStatus}
                                onWalkoverWinnerChange={updateWalkoverWinner}
                                refereeOptions={refereeOptions}
                                homeRoster={homeRoster}
                                awayRoster={awayRoster}
                                participantSelection={participantSelection}
                                onToggleParticipant={toggleParticipantSelection}
                                onSelectAllParticipants={selectAllParticipants}
                                onClearParticipants={clearParticipants}
                                homeSelectedRows={homeSelectedRows}
                                awaySelectedRows={awaySelectedRows}
                                playerStatsForm={playerStatsForm}
                                mvpPlayerId={mvpPlayerId}
                                onToggleMvp={toggleMvp}
                                onStatChange={updatePlayerStat}
                                homeTotals={homeTotals}
                                awayTotals={awayTotals}
                                homeUnassignedGoals={homeUnassignedGoals}
                                awayUnassignedGoals={awayUnassignedGoals}
                                onSave={() => saveMatch(match)}
                                saving={savingMatchData}
                              />
                            </div>

                          <div className="hidden md:grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-7 gap-3 items-end">
                            <AdminFormField
                              label={`Bramki ${match.home_team_abbr || match.home_team_name}`}
                              name="home_goals"
                              type="number"
                              value={scoreForm.home_goals}
                              onChange={(e) => setScoreForm((prev) => ({ ...prev, home_goals: e.target.value }))}
                              darkMode={darkMode}
                              min={0}
                            />
                            <AdminFormField
                              label={`Bramki ${match.away_team_abbr || match.away_team_name}`}
                              name="away_goals"
                              type="number"
                              value={scoreForm.away_goals}
                              onChange={(e) => setScoreForm((prev) => ({ ...prev, away_goals: e.target.value }))}
                              darkMode={darkMode}
                              min={0}
                            />
                            <AdminFormField
                              label="Status"
                              name="status"
                              type="select"
                              value={scoreForm.status}
                              onChange={(e) => updateScoreStatus(e.target.value)}
                              darkMode={darkMode}
                              options={[
                                { value: "scheduled", label: "Zaplanowany" },
                                { value: "completed", label: "Zakonczony" },
                                { value: "walkover", label: "Walkower" },
                                { value: "postponed", label: "Przelozony" },
                                { value: "cancelled", label: "Odwolany" },
                                { value: "unplayed", label: "Nierozegrany" },
                              ]}
                            />
                            {scoreForm.status === "walkover" && (
                              <AdminFormField
                                label="Wygral walkowerem"
                                name="walkover_winner"
                                type="select"
                                value={scoreForm.walkover_winner || "home"}
                                onChange={(e) => updateWalkoverWinner(e.target.value)}
                                darkMode={darkMode}
                                options={[
                                  { value: "home", label: match.home_team_name },
                                  { value: "away", label: match.away_team_name },
                                ]}
                              />
                            )}
                            <AdminFormField
                              label="Sedzia"
                              name="referee_id"
                              type="select"
                              value={scoreForm.referee_id || ""}
                              onChange={(e) => setScoreForm((prev) => ({ ...prev, referee_id: e.target.value }))}
                              darkMode={darkMode}
                              options={refereeOptions}
                            />
                            <div className="sm:col-span-2 xl:col-span-2">
                              <AdminFormField
                                label="Link do nagrania"
                                name="video_url"
                                type="url"
                                value={scoreForm.video_url || ""}
                                onChange={(e) => setScoreForm((prev) => ({ ...prev, video_url: e.target.value }))}
                                darkMode={darkMode}
                                placeholder="https://..."
                                helpText="Link otwierany po kliknieciu ikonki kamerki przy meczu."
                              />
                            </div>
                            <button
                              type="button"
                              onClick={() => saveMatch(match)}
                              disabled={savingMatchData}
                              className="flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-green-500 text-black font-medium text-sm hover:bg-green-400 min-h-[48px] sm:col-span-2 xl:col-span-1 disabled:opacity-60"
                            >
                              {savingMatchData ? <Loader2 size={14} className="animate-spin" /> : <Save size={14} />}
                              Zapisz mecz
                            </button>
                          </div>
                          </>
                        ) : (
                          <div className={`flex items-center gap-4 text-sm py-1 ${textMuted}`}>
                            <span>
                              Wynik:{" "}
                              <strong className={darkMode ? "text-white" : "text-gray-900"}>
                                {match.home_goals ?? "—"} : {match.away_goals ?? "—"}
                              </strong>
                            </span>
                            <span>Status: {statusLabel(match.status)}</span>
                            {match.referee && <span>Sedzia: {match.referee}</span>}
                          </div>
                        )}

                        <div className={`text-xs ${textMuted}`}>
                          Ostatnia edycja wyniku:{" "}
                          <span className={darkMode ? "text-gray-200 font-semibold" : "text-gray-700 font-semibold"}>
                            {resultEditorName}
                          </span>
                          {resultEditTime ? <span> - {resultEditTime}</span> : null}
                        </div>

                        <div className={`rounded-xl border p-4 ${isEditable ? "hidden md:block" : ""} ${darkMode ? "border-white/10 bg-black/10" : "border-gray-200 bg-gray-50"}`}>
                          <div className="font-semibold text-sm">Dobor zawodnikow i statystyki meczu</div>
                          <p className={`text-xs mt-1 ${textMuted}`}>
                            Wynik meczu mozesz zapisac bez skladu. Zawodnikow wybieraj tylko wtedy, gdy chcesz dopisac statystyki lub MVP.
                            Puste pola i zera sa traktowane tak samo. Nie musisz rozpisywac wszystkich goli na zawodnikow - jesli wpiszesz mniej strzelcow niz wynika z rezultatu, zapisze sie sam wynik meczu. Asysty zapisujemy tylko do goli wpisanych zawodnikom.
                          </p>

                          {scoreForm.status !== "completed" && (
                            <div className={`mt-3 rounded-xl border px-3 py-2 text-sm ${darkMode ? "border-blue-400/20 bg-blue-500/10 text-blue-200" : "border-blue-200 bg-blue-50 text-blue-800"}`}>
                              Statystyki zawodnikow sa zapisywane tylko dla meczu ze statusem "Zakonczony". Przy innych statusach zapis wyniku wyczysci sklad, zdarzenia i MVP.
                            </div>
                          )}

                          <div className="mt-4 grid lg:grid-cols-2 gap-4">
                            <ParticipantSelector
                              title="Uczestnicy gospodarzy"
                              teamKey="home"
                              teamName={match.home_team_name}
                              roster={homeRoster}
                              selectedIds={participantSelection.home}
                              draftIds={participantDrafts.home}
                              open={pickerOpen === "home"}
                              onToggleOpen={togglePicker}
                              onTogglePlayer={toggleDraftPlayer}
                              onApply={applyParticipantSelection}
                              darkMode={darkMode}
                              disabled={!isEditable || savingMatchData}
                            />
                            <ParticipantSelector
                              title="Uczestnicy gosci"
                              teamKey="away"
                              teamName={match.away_team_name}
                              roster={awayRoster}
                              selectedIds={participantSelection.away}
                              draftIds={participantDrafts.away}
                              open={pickerOpen === "away"}
                              onToggleOpen={togglePicker}
                              onTogglePlayer={toggleDraftPlayer}
                              onApply={applyParticipantSelection}
                              darkMode={darkMode}
                              disabled={!isEditable || savingMatchData}
                            />
                          </div>

                          <div className="mt-4 grid xl:grid-cols-2 gap-4">
                            <ParticipantStatsTable
                              title={`${match.home_team_name} • uczestnicy`}
                              players={homeSelectedRows}
                              playerStatsForm={playerStatsForm}
                              mvpPlayerId={mvpPlayerId}
                              onToggleMvp={toggleMvp}
                              onStatChange={updatePlayerStat}
                              darkMode={darkMode}
                              disabled={!isEditable || savingMatchData || scoreForm.status !== "completed"}
                            />
                            <ParticipantStatsTable
                              title={`${match.away_team_name} • uczestnicy`}
                              players={awaySelectedRows}
                              playerStatsForm={playerStatsForm}
                              mvpPlayerId={mvpPlayerId}
                              onToggleMvp={toggleMvp}
                              onStatChange={updatePlayerStat}
                              darkMode={darkMode}
                              disabled={!isEditable || savingMatchData || scoreForm.status !== "completed"}
                            />
                          </div>

                          <div className={`mt-4 flex flex-wrap gap-2 text-xs ${textMuted}`}>
                            <span className={`px-2 py-1 rounded-full border ${darkMode ? "border-white/10 bg-white/5" : "border-gray-200 bg-white"}`}>
                              {match.home_team_name}: gole {homeTotals.goals}, asysty {homeTotals.assists}, ZK {homeTotals.yellow}, CZK {homeTotals.red}
                            </span>
                            <span className={`px-2 py-1 rounded-full border ${darkMode ? "border-white/10 bg-white/5" : "border-gray-200 bg-white"}`}>
                              {match.away_team_name}: gole {awayTotals.goals}, asysty {awayTotals.assists}, ZK {awayTotals.yellow}, CZK {awayTotals.red}
                            </span>
                            {homeUnassignedGoals > 0 && (
                              <span className={`px-2 py-1 rounded-full border ${darkMode ? "border-blue-400/20 bg-blue-500/10 text-blue-200" : "border-blue-200 bg-blue-50 text-blue-800"}`}>
                                {match.home_team_name}: nierozpisane gole {homeUnassignedGoals}
                              </span>
                            )}
                            {awayUnassignedGoals > 0 && (
                              <span className={`px-2 py-1 rounded-full border ${darkMode ? "border-blue-400/20 bg-blue-500/10 text-blue-200" : "border-blue-200 bg-blue-50 text-blue-800"}`}>
                                {match.away_team_name}: nierozpisane gole {awayUnassignedGoals}
                              </span>
                            )}
                            {mvpPlayerId && (
                              <span className={`px-2 py-1 rounded-full border ${darkMode ? "border-amber-400/20 bg-amber-500/10 text-amber-200" : "border-amber-300 bg-amber-50 text-amber-800"}`}>
                                MVP wybrany
                              </span>
                            )}
                            <span>
                              Aktualny zapis: {matchEvents.length} zdarzen, {matchLineups.length} pozycji w skladzie.
                            </span>
                          </div>

                          {isEditable && (
                            <button
                              type="button"
                              onClick={() => saveMatch(match)}
                              disabled={savingMatchData}
                              className="md:hidden mt-4 w-full flex items-center justify-center gap-2 px-4 py-3 rounded-xl bg-green-500 text-black font-semibold hover:bg-green-400 min-h-[50px] disabled:opacity-60"
                            >
                              {savingMatchData ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />}
                              Zapisz mecz
                            </button>
                          )}
                        </div>

                        <AdminMatchGalleryManager
                          match={match}
                          darkMode={darkMode}
                          onAlert={setAlert}
                        />
                      </>
                    )}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}
